      {/* Payment Breakup */}
      <div style={{ marginBottom: 20 }} data-html2pdf-page-break="before">
        <h3 style={{ fontSize: 13, fontWeight: 600, marginBottom: 6 }}>Payment Breakup</h3>
        <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
          <PieChart width={300} height={CHART_H}>
            <Pie
              data={pieData}
              cx={150}
              cy={130}
              outerRadius={110}
              dataKey="value"
              label={({ cx, cy, midAngle, innerRadius, outerRadius, index }: { cx: number; cy: number; midAngle: number; innerRadius: number; outerRadius: number; index: number }) => {
                const RADIAN = Math.PI / 180;
                const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
                const x = cx + radius * Math.cos(-midAngle * RADIAN);
                const y = cy + radius * Math.sin(-midAngle * RADIAN);
                return (
                  <text x={x} y={y} fill="white" textAnchor="middle" dominantBaseline="central" fontWeight="bold" fontSize={13}>
                    {((pieData[index].value / pieTotal) * 100).toFixed(1)}%
                  </text>
                );
              }}
              labelLine={false}
            >
              {pieData.map((_, i) => <Cell key={i} fill={PIE_COLORS[i]} />)}
            </Pie>
            <Tooltip formatter={(value: number | string) => formatCurrency(Number(value))} />
          </PieChart>
          <div>
            <div style={{ marginBottom: 6 }}>
              <span style={{ display: 'inline-block', width: 12, height: 12, borderRadius: '50%', background: '#22c55e', marginRight: 6, verticalAlign: 'middle' }} />
              Principal: {formatCurrency(principalPaid)}
            </div>
            <div>
              <span style={{ display: 'inline-block', width: 12, height: 12, borderRadius: '50%', background: '#ef4444', marginRight: 6, verticalAlign: 'middle' }} />
              Interest: {formatCurrency(wp.totalInterest)}
            </div>
          </div>
        </div>
      </div>

      {/* Yearly Summary */}
      <div style={{ marginBottom: 20 }}>
        <h3 style={{ fontSize: 13, fontWeight: 600, marginBottom: 6 }}>Yearly Summary</h3>
        <BarChart width={CHART_W} height={CHART_H} data={yearlyData}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="year" tick={{ fontSize: 10 }} />
          <YAxis tickFormatter={(v) => formatCurrencyShort(v)} width={80} tick={{ fontSize: 10 }} />
          <Tooltip formatter={(value: number | string) => formatCurrency(Number(value))} labelFormatter={(l) => `Year ${l}`} />
          <Legend wrapperStyle={{ fontSize: 10 }} />
          <Bar dataKey="principal" name="Principal + Prepayment" fill="#22c55e" />
          <Bar dataKey="interest" name="Interest" fill="#ef4444" />
        </BarChart>
      </div>

      {/* === SECTION 4: Amortization Schedule === */}
      <h2 style={{ fontSize: 16, fontWeight: 700, margin: '20px 0 10px', borderBottom: '2px solid #2563eb', paddingBottom: 4 }}>
        Amortization Schedule ({schedule.length} months)
      </h2>
      <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 10 }}>
        <thead>
          <tr style={{ borderBottom: '2px solid #374151', background: '#f9fafb' }}>
            <th style={{ padding: '4px 3px', textAlign: 'left', fontWeight: 600 }}>#</th>
            <th style={{ padding: '4px 3px', textAlign: 'left', fontWeight: 600 }}>Date</th>
            {hasRateChanges && <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Rate</th>}
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Opening</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Interest</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Principal</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Pre-Pay</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Total</th>
            <th style={{ padding: '4px 3px', textAlign: 'right', fontWeight: 600 }}>Closing</th>
          </tr>
        </thead>
        <tbody>
          {schedule.map((row) => {
            const rateChanged = hasRateChanges && row.month > 1 &&
              row.annualRate !== schedule[row.month - 2]?.annualRate;
            let bg = '#fff';
            if (row.prePayment > 0) bg = '#f0fdf4'; // green-50
            else if (rateChanged) bg = '#eef2ff'; // indigo-50

            return (
              <tr key={row.month} style={{ borderBottom: '1px solid #e5e7eb', background: bg }}>
                <td style={{ padding: '3px' }}>{row.month}</td>
                <td style={{ padding: '3px', whiteSpace: 'nowrap' }}>{formatDate(row.date)}</td>
                {hasRateChanges && (
                  <td style={{ padding: '3px', textAlign: 'right', fontWeight: rateChanged ? 700 : 400, color: rateChanged ? '#4338ca' : undefined }}>
                    {row.annualRate}%
                  </td>
                )}
                <td style={{ padding: '3px', textAlign: 'right' }}>{formatCurrency(row.openingBalance)}</td>
                <td style={{ padding: '3px', textAlign: 'right', color: '#dc2626' }}>{formatCurrency(row.interestComponent)}</td>
                <td style={{ padding: '3px', textAlign: 'right', color: '#15803d' }}>{formatCurrency(row.principalComponent)}</td>
                <td style={{ padding: '3px', textAlign: 'right', color: row.prePayment > 0 ? '#2563eb' : '#d1d5db' }}>
                  {row.prePayment > 0 ? formatCurrency(row.prePayment) : '-'}
                </td>
                <td style={{ padding: '3px', textAlign: 'right' }}>{formatCurrency(row.totalPayment)}</td>
                <td style={{ padding: '3px', textAlign: 'right', fontWeight: 600 }}>{formatCurrency(row.closingBalance)}</td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
});

import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip } from 'recharts';
import type { LoanSummary } from '../../types/loan';
import { formatCurrency } from '../../utils/formatters';

interface Props {
  summary: LoanSummary;
}

const COLORS = ['#22c55e', '#ef4444'];

export function PaymentBreakupChart({ summary }: Props) {
  const { withPrePayments: wp } = summary;
  const principalPaid = wp.totalAmountPaid - wp.totalInterest;

  const data = [
    { name: 'Principal', value: Math.round(principalPaid) },
    { name: 'Interest', value: Math.round(wp.totalInterest) },
  ];

  const total = data[0].value + data[1].value;

  const renderLabel = ({
    cx,
    cy,
    midAngle,
    innerRadius,
    outerRadius,
    index,
  }: {
    cx: number;
    cy: number;
    midAngle: number;
    innerRadius: number;
    outerRadius: number;
    index: number;
  }) => {
    const RADIAN = Math.PI / 180;
    const radius = innerRadius + (outerRadius - innerRadius) * 0.5;
    const x = cx + radius * Math.cos(-midAngle * RADIAN);
    const y = cy + radius * Math.sin(-midAngle * RADIAN);
    const pct = ((data[index].value / total) * 100).toFixed(1);

    return (
      <text
        x={x}
        y={y}
        fill="white"
        textAnchor="middle"
        dominantBaseline="central"
        fontWeight="bold"
        fontSize={14}
      >
        {pct}%
      </text>
    );
  };

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h3 className="mb-4 text-lg font-semibold text-gray-900">
        Payment Breakup
      </h3>
      <ResponsiveContainer width="100%" height={350}>
        <PieChart>
          <Pie
            data={data}
            cx="50%"
            cy="50%"
            outerRadius={130}
            dataKey="value"
            labelLine={false}
            label={renderLabel}
          >
            {data.map((_, index) => (
              <Cell key={index} fill={COLORS[index]} />
            ))}
          </Pie>
          <Tooltip formatter={(value: number | string) => formatCurrency(Number(value))} />
        </PieChart>
      </ResponsiveContainer>
      <div className="mt-2 flex justify-center gap-6 text-sm">
        <span className="flex items-center gap-1.5">
          <span className="inline-block h-3 w-3 rounded-full bg-green-500" />
          Principal: {formatCurrency(principalPaid)}
        </span>
        <span className="flex items-center gap-1.5">
          <span className="inline-block h-3 w-3 rounded-full bg-red-500" />
          Interest: {formatCurrency(wp.totalInterest)}
        </span>
      </div>
    </div>
  );
}

import { useMemo } from "react";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from "recharts";
import type { LoanSummary, AmortizationResult } from "../../types/loan";
import { formatCurrency, formatDate } from "../../utils/formatters";

interface Props {
  summary: LoanSummary;
  simulatedResult?: AmortizationResult | null;
}

function buildCumulativeData(
  summary: LoanSummary,
  simulatedResult?: AmortizationResult | null,
) {
  const { withPrePayments, withoutPrePayments } = summary;

  const maxLen = Math.max(
    withPrePayments.schedule.length,
    withoutPrePayments.schedule.length,
    simulatedResult?.schedule.length ?? 0,
  );

  let cumOriginal = 0;
  let cumActual = 0;
  let cumSimulated = 0;

  return Array.from({ length: maxLen }, (_, i) => {
    const dateStr =
      withoutPrePayments.schedule[i]?.date ??
      withPrePayments.schedule[i]?.date ??
      simulatedResult?.schedule[i]?.date ??
      "";

    cumOriginal += withoutPrePayments.schedule[i]?.interestComponent ?? 0;
    cumActual += withPrePayments.schedule[i]?.interestComponent ?? 0;
    if (simulatedResult) {
      cumSimulated += simulatedResult.schedule[i]?.interestComponent ?? 0;
    }

    const entry: Record<string, number | string> = {
      month: i + 1,
      label: dateStr ? formatDate(dateStr) : "",
      original: Math.round(cumOriginal),
      actual: Math.round(cumActual),
    };
    if (simulatedResult) {
      entry.simulated = Math.round(cumSimulated);
    }
    return entry;
  });
}

export function CumulativeInterestChart({ summary, simulatedResult }: Props) {
  const data = useMemo(
    () => buildCumulativeData(summary, simulatedResult),
    [summary, simulatedResult],
  );

  return (
    <div className="rounded-xl border border-gray-200 bg-white p-6 shadow-sm">
      <h3 className="mb-4 text-lg font-semibold text-gray-900">
        Cumulative Interest Paid
      </h3>
      <ResponsiveContainer width="100%" height={350}>
        <AreaChart data={data}>
          <defs>
            <linearGradient id="gradOriginal" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#94a3b8" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#94a3b8" stopOpacity={0} />
            </linearGradient>
            <linearGradient id="gradActual" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#ef4444" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#ef4444" stopOpacity={0} />
            </linearGradient>
            <linearGradient id="gradSimulated" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#f59e0b" stopOpacity={0.3} />
              <stop offset="95%" stopColor="#f59e0b" stopOpacity={0} />
            </linearGradient>
          </defs>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis
            dataKey="month"
            label={{ value: "Month", position: "insideBottom", offset: -5 }}
          />
          <YAxis tickFormatter={(v) => formatCurrency(v)} width={100} />
          <Tooltip
            formatter={(value: number | string) => formatCurrency(Number(value))}
            labelFormatter={(
              _: string,
              payload: Array<{ payload?: { label?: string } }>,
            ) => payload?.[0]?.payload?.label || ""}
          />
          <Legend />
          <Area
            type="monotone"
            dataKey="original"
            name="Original Schedule"
            stroke="#94a3b8"
            fill="url(#gradOriginal)"
            strokeWidth={2}
          />
          <Area
            type="monotone"
            dataKey="actual"
            name="Actual (with adjustments)"
            stroke="#ef4444"
            fill="url(#gradActual)"
            strokeWidth={2}
          />
          {simulatedResult && (
            <Area
              type="monotone"
              dataKey="simulated"
              name="Simulated (what-if)"
              stroke="#f59e0b"
              fill="url(#gradSimulated)"
              strokeWidth={2}
              strokeDasharray="6 3"
            />
          )}
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}

