          />
          <YAxis
            tickFormatter={(v) => formatCurrency(v)}
            width={100}
          />
          <Tooltip
            formatter={(value) => formatCurrency(Number(value))}
            labelFormatter={(_: string, payload: Array<{ payload?: { label?: string } }>) => payload?.[0]?.payload?.label || ''}
          />
          <Legend />
          {currentMonthIndex !== null && (
            <ReferenceLine
              x={currentMonthIndex}
              stroke="#2563eb"
              strokeWidth={2}
              strokeDasharray="4 4"
              label={{ value: 'Now', position: 'top', fill: '#2563eb', fontWeight: 'bold' }}
            />
          )}
          <Line
            type="monotone"
            dataKey="withoutPP"
            name="Original Schedule"
            stroke="#94a3b8"
            strokeWidth={2}
            dot={false}
          />
          <Line
            type="monotone"
            dataKey="withPP"
            name="Actual (with adjustments)"
            stroke="#2563eb"
            strokeWidth={2}
            dot={false}
          />
          {simulatedResult && (
            <Line
              type="monotone"
              dataKey="simulated"
              name="Simulated (what-if)"
              stroke="#f59e0b"
              strokeWidth={2}
              strokeDasharray="6 3"
              dot={false}
            />
          )}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}

