                <th style={{ padding: '4px 8px', textAlign: 'left', fontWeight: 600 }}>Effective Date</th>
                <th style={{ padding: '4px 8px', textAlign: 'right', fontWeight: 600 }}>New Rate</th>
              </tr>
            </thead>
            <tbody>
              {rateChanges.map((rc) => (
                <tr key={rc.id} style={{ borderBottom: '1px solid #e5e7eb' }}>
                  <td style={{ padding: '4px 8px' }}>{formatDateFull(rc.date)}</td>
                  <td style={{ padding: '4px 8px', textAlign: 'right' }}>{rc.newRate}%</td>
                </tr>
              ))}
            </tbody>
          </table>
