  1→import { NextResponse } from 'next/server';
  2→import { calculateAmortization, generateSummary, validateLoan } from '@/utils/amortization';
  3→import type { LoanInput, PrePayment, RateChange } from '@/types/loan';
  4→import type { Recommendation } from '@/types/recommendation';
  5→import { format, addMonths, parseISO } from 'date-fns';
  6→
  7→interface RequestBody {
  8→  loan: LoanInput;
  9→  prePayments: PrePayment[];
 10→  rateChanges: RateChange[];
 11→}
 12→
 13→function assignPriority(interestSaved: number): 'high' | 'medium' | 'low' {
 14→  if (interestSaved >= 200000) return 'high';
 15→  if (interestSaved >= 50000) return 'medium';
 16→  return 'low';
 17→}
 18→
 19→function generatePrepaymentRecommendation(
 20→  loan: LoanInput,
 21→  prePayments: PrePayment[],
 22→  rateChanges: RateChange[],
 23→  baseline: ReturnType<typeof calculateAmortization>
 24→): Recommendation | null {
 25→  const percentages = [5, 10, 15, 20];
 26→  const remainingBalance = baseline.schedule[0]?.openingBalance ?? loan.principal;
 27→
 28→  let best: Recommendation | null = null;
 29→
 30→  for (const pct of percentages) {
 31→    const ppAmount = Math.round(remainingBalance * (pct / 100));
 32→    const ppDate = format(addMonths(parseISO(loan.startDate), 12), 'yyyy-MM-dd');
 33→    const pp: PrePayment = { id: `sim-pp-${pct}`, date: ppDate, amount: ppAmount };
 34→    const result = calculateAmortization(loan, [...prePayments, pp], rateChanges);
 35→    const interestSaved = Math.round((baseline.totalInterest - result.totalInterest) * 100) / 100;
 36→    const monthsSaved = baseline.totalMonths - result.totalMonths;
 37→
 38→    if (interestSaved > 0 && (!best || interestSaved > best.impact.interestSaved)) {
 39→      best = {
 40→        id: `prepayment-${pct}`,
 41→        type: 'prepayment',
 42→        title: `${pct}% Lump Sum Prepayment`,
 43→        description: `A one-time prepayment of ${formatINR(ppAmount)} (${pct}% of principal) in year 1 would save ${formatINR(interestSaved)} in interest and close the loan ${monthsSaved} months earlier.`,
 44→        impact: { interestSaved, monthsSaved, newClosureDate: result.closureDate },
 45→        priority: assignPriority(interestSaved),
 46→      };
 47→    }
 48→  }
 49→
 50→  return best;
 51→}
 52→
 53→function generateEmiIncreaseRecommendation(
 54→  loan: LoanInput,
 55→  prePayments: PrePayment[],
 56→  rateChanges: RateChange[],
 57→  baseline: ReturnType<typeof calculateAmortization>
 58→): Recommendation | null {
 59→  const increases = [5, 10, 15, 20];
 60→  let best: Recommendation | null = null;
 61→
 62→  for (const pct of increases) {
 63→    const newEmi = Math.round(loan.emi * (1 + pct / 100));
 64→    const modifiedLoan = { ...loan, emi: newEmi };
 65→    const validationError = validateLoan(modifiedLoan);
 66→    if (validationError) continue;
 67→
 68→    const result = calculateAmortization(modifiedLoan, prePayments, rateChanges);
 69→    const interestSaved = Math.round((baseline.totalInterest - result.totalInterest) * 100) / 100;
 70→    const monthsSaved = baseline.totalMonths - result.totalMonths;
 71→
 72→    if (interestSaved > 0 && (!best || interestSaved > best.impact.interestSaved)) {
 73→      best = {
 74→        id: `emi-increase-${pct}`,
 75→        type: 'emi_increase',
 76→        title: `Increase EMI by ${pct}%`,
 77→        description: `Raising your EMI from ${formatINR(loan.emi)} to ${formatINR(newEmi)} (+${pct}%) would save ${formatINR(interestSaved)} in interest and finish ${monthsSaved} months sooner.`,
 78→        impact: { interestSaved, monthsSaved, newClosureDate: result.closureDate },
 79→        priority: assignPriority(interestSaved),
 80→      };
 81→    }
 82→  }
 83→
 84→  return best;
 85→}
 86→
 87→function generateLumpSumTimingRecommendation(
 88→  loan: LoanInput,
 89→  prePayments: PrePayment[],
 90→  rateChanges: RateChange[],
 91→  baseline: ReturnType<typeof calculateAmortization>
 92→): Recommendation | null {
 93→  const lumpSum = loan.emi * 2;
 94→  const ppDate = format(addMonths(new Date(), 0), 'yyyy-MM-dd');
 95→  const pp: PrePayment = { id: 'sim-ls-now', date: ppDate, amount: lumpSum };
 96→  const result = calculateAmortization(loan, [...prePayments, pp], rateChanges);
 97→  const interestSaved = Math.round((baseline.totalInterest - result.totalInterest) * 100) / 100;
 98→  const monthsSaved = baseline.totalMonths - result.totalMonths;
 99→
100→  if (interestSaved <= 0) return null;
101→
102→  return {
103→    id: 'lump-sum-now',
104→    type: 'lump_sum_timing',
105→    title: `Pay ${formatINR(lumpSum)} now`,
106→    description: `A lump sum of ${formatINR(lumpSum)} (2x EMI) paid now saves ${formatINR(interestSaved)} in interest and ${monthsSaved} months off tenure. Earlier is always better!`,
107→    impact: { interestSaved, monthsSaved, newClosureDate: result.closureDate },
108→    priority: assignPriority(interestSaved),
109→  };
110→}
111→
112→function formatINR(amount: number): string {
113→  return new Intl.NumberFormat('en-IN', {
114→    style: 'currency',
115→    currency: 'INR',
116→    maximumFractionDigits: 0,
117→  }).format(amount);
118→}
119→
120→export async function POST(request: Request) {
121→  try {
122→    const body: RequestBody = await request.json();
123→    const { loan, prePayments = [], rateChanges = [] } = body;
124→
125→    if (!loan) {
126→      return NextResponse.json({ error: 'Loan data is required' }, { status: 400 });
127→    }
128→
129→    const validationError = validateLoan(loan);
130→    if (validationError) {
131→      return NextResponse.json({ error: validationError }, { status: 400 });
132→    }
133→
134→    const summary = generateSummary(loan, prePayments, rateChanges);
135→    const baseline = summary.withPrePayments;
136→
137→    const recommendations: Recommendation[] = [
138→      generatePrepaymentRecommendation(loan, prePayments, rateChanges, baseline),
139→      generateEmiIncreaseRecommendation(loan, prePayments, rateChanges, baseline),
140→      generateLumpSumTimingRecommendation(loan, prePayments, rateChanges, baseline),
141→    ].filter((r): r is Recommendation => r !== null);
142→
143→    // Sort by interest saved (highest first)
144→    recommendations.sort((a, b) => b.impact.interestSaved - a.impact.interestSaved);
145→
146→    return NextResponse.json({
147→      recommendations,
148→      currentSummary: {
149→        totalInterest: baseline.totalInterest,
150→        totalMonths: baseline.totalMonths,
151→        closureDate: baseline.closureDate,
152→      },
153→    });
154→  } catch {
155→    return NextResponse.json({ error: 'Invalid request body' }, { status: 400 });
156→  }
157→}
