 1→import { useState, useEffect, useRef, useCallback } from 'react';
 2→import type { LoanInput, PrePayment, RateChange } from '../types/loan';
 3→import { loadState, saveState } from '../utils/storage';
 4→
 5→export function useLoanData() {
 6→  const [loan, setLoan] = useState<LoanInput | null>(null);
 7→  const [prePayments, setPrePayments] = useState<PrePayment[]>([]);
 8→  const [rateChanges, setRateChanges] = useState<RateChange[]>([]);
 9→  const initialized = useRef(false);
10→  const saveTimer = useRef<ReturnType<typeof setTimeout>>(undefined);
11→
12→  // Load from localStorage on mount
13→  useEffect(() => {
14→    const saved = loadState();
15→    if (saved.loan) setLoan(saved.loan);
16→    if (saved.prePayments.length) setPrePayments(saved.prePayments);
17→    if (saved.rateChanges.length) setRateChanges(saved.rateChanges);
18→    initialized.current = true;
19→  }, []);
20→
21→  // Save to localStorage (debounced)
22→  useEffect(() => {
23→    if (!initialized.current) return;
24→    clearTimeout(saveTimer.current);
25→    saveTimer.current = setTimeout(() => {
26→      saveState({ loan, prePayments, rateChanges });
27→    }, 300);
28→    return () => clearTimeout(saveTimer.current);
29→  }, [loan, prePayments, rateChanges]);
30→
31→  const addPrePayment = useCallback((pp: PrePayment) => {
32→    setPrePayments((prev) => [...prev, pp]);
33→  }, []);
34→
35→  const removePrePayment = useCallback((id: string) => {
36→    setPrePayments((prev) => prev.filter((pp) => pp.id !== id));
37→  }, []);
38→
39→  const addRateChange = useCallback((rc: RateChange) => {
40→    setRateChanges((prev) => [...prev, rc]);
41→  }, []);
42→
43→  const removeRateChange = useCallback((id: string) => {
44→    setRateChanges((prev) => prev.filter((rc) => rc.id !== id));
45→  }, []);
46→
47→  return {
48→    loan, setLoan,
49→    prePayments, addPrePayment, removePrePayment,
50→    rateChanges, addRateChange, removeRateChange,
51→  };
52→}
