 1→import { useRef, useState, useCallback, useEffect } from 'react';
 2→
 3→export function useExportPdf() {
 4→  const reportRef = useRef<HTMLDivElement>(null);
 5→  const [isGenerating, setIsGenerating] = useState(false);
 6→  const filenameRef = useRef<string | null>(null);
 7→
 8→  // When isGenerating becomes true and PdfReport mounts, wait for
 9→  // Recharts to paint, then capture to PDF.
10→  useEffect(() => {
11→    if (!isGenerating) return;
12→
13→    let cancelled = false;
14→
15→    (async () => {
16→      // Give Recharts time to mount & paint SVGs (needs ≥1 frame + layout)
17→      await new Promise((r) => setTimeout(r, 1000));
18→      const el = reportRef.current;
19→      if (cancelled || !el) {
20→        setIsGenerating(false);
21→        return;
22→      }
23→
24→      try {
25→        const html2pdf = (await import('html2pdf.js')).default;
26→        const date = new Date().toISOString().split('T')[0];
27→        const name = filenameRef.current ?? `loan-report-${date}.pdf`;
28→
29→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
30→        await (html2pdf() as any)
31→          .set({
32→            margin: 10,
33→            filename: name,
34→            image: { type: 'jpeg', quality: 0.98 },
35→            html2canvas: { scale: 2, useCORS: true, logging: false },
36→            jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
37→            pagebreak: { mode: ['avoid-all', 'css', 'legacy'] },
38→          })
39→          .from(el)
40→          .save();
41→      } finally {
42→        filenameRef.current = null;
43→        if (!cancelled) setIsGenerating(false);
44→      }
45→    })();
46→
47→    return () => {
48→      cancelled = true;
49→    };
50→  }, [isGenerating]);
51→
52→  const exportPdf = useCallback(
53→    (filename?: string) => {
54→      if (isGenerating) return;
55→      filenameRef.current = filename ?? null;
56→      setIsGenerating(true);
57→    },
58→    [isGenerating],
59→  );
60→
61→  return { reportRef, isGenerating, exportPdf };
62→}
